import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.google.com/google-ads/api/rest/auth";
const PLACEHOLDER_VALUE =
  "ya29.A0CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Google Ads API REST docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:google-ads",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const googleAdsFirewall = {",
    '  name: "google-ads",',
    '  description: "Google Ads API",',
    "  placeholders: {",
    `    GOOGLE_ADS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    `    GOOGLE_ADS_DEVELOPER_TOKEN: "${PLACEHOLDER_VALUE}",`,
    `    GOOGLE_ADS_LOGIN_CUSTOMER_ID: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://googleads.googleapis.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.GOOGLE_ADS_TOKEN }}",',
    '          "developer-token": "${{ secrets.GOOGLE_ADS_DEVELOPER_TOKEN }}",',
    '          "login-customer-id": "${{ secrets.GOOGLE_ADS_LOGIN_CUSTOMER_ID }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Google Ads firewall config...");
  const ts = generateTypeScript();
  writeOutput("google-ads", ts, import.meta.dirname);
}
